    "displayName": "Analyze Child Mood Patterns",
    "description": "Identify patterns between mood ratings and preceding events, activities, sleep, and other factors",
    "inputs": [
      {
        "name": "childName",
        "valueType": "text",
        "source": "slot",
        "required": true
      },
      {
        "name": "startDate",
        "valueType": "date",
        "source": "slot",
        "required": false
      },
